import Foundation

@objc protocol BLEKeyParserProtocol {
    func parseBleData(_ data: Data)
    func handleVehicleState(msg: BleCanMessage)
    func handleCanEvent(msg: BleCanMessage) 
}

protocol BLEDataParserCanEventDelegate: NSObjectProtocol {
    // MARK: 泊车
    // parkingState - 泊车状态信号
    // parkingExpType - 泊车失败或暂停的原因
    // gearValue - 泊车挂档信号
    // parkingAnimation -
    // parkingProcess -
    // E28 单帧数据不完整，所以允许参数传空，业务方自行合并处理
    func didReceiveCanEventParking(parkingMsg: CanEvent)
    // MARK: 泊车碰撞检测
    func didReceiveCanEventParkingCollision(parkingCollisionMsg: CanEvent)

    func didReceiveAuth0Response(rand01: UInt32?, rand1:UInt32)

    func didReceiveAuthResult(authResult: Int, failedReason: Int?)
}

protocol BLECduAccountLoginDelegate: BLEDataParserResultDelegate {
    // 大屏联登反馈
    func didReceiveCanEventCDUAccountLoginState(signalValue: Int)
}

protocol BLECarControlDelegate: BLEDataParserResultDelegate {
    // 蓝牙车控指令结果返回，result - 200 为执行成功
    func didReceiveCanEventCarControlResult(controlId: Int, result: Int)
}


protocol BLEDataParserResultDelegate:BLEDataParserCanEventDelegate {
    // 蓝牙车态解析回调
    func didReceiveVehicleState(state: VehicleState);
}

class BLEDataParser: BLEKeyParserProtocol  {

    func cppParser(_ data: Data) -> String? {
        return ""
    }

    var vehicleTypeCode: String = ""
    weak var delegate: BLEDataParserResultDelegate?


    func parseBleData(_ data: Data) {
        var msg = self.cppParser(data)
        self.handleParserData(msg)
    }

    init(vehicleTypeCode: String,delegate: BLEDataParserResultDelegate) {
        self.vehicleTypeCode = vehicleTypeCode
        self.delegate = delegate
    }
}

