//
//  BleKeyV3AuthFlow.swift
//  XPVehicleSDK
//
//  Created by huzy2 on 2024/8/18.
//

import Foundation
import Combine
import XPDataProcessor

class BleKeyV3AuthFlow :BleAuthFlow {
    var indicatorHexStartIndex: String.Index
    var indicatorHexEndIndex: String.Index
    var keyIdHexStartIndex: String.Index
    var keyIdHexEndIndex: String.Index
    var authKeyHexStartIndex: String.Index
    var authKeyHexEndIndex: String.Index
    var certMessageHexStartIndex: String.Index
    var certMessageHexEndIndex: String.Index

    let certMessage: String
    let uid: UInt64

    var hexKeyId: String?
    var hexAuthKey: String?
    var rand0: UInt32?
    var rand12: UInt32?
    var sessionKey: Data?
    var hmacKey: Data?

    let authFactorBlock: BleAuthFlowEncryptFactorBlock
    var keySetting: XiaopengKeyDataSetting

    var passSubject1: PassthroughSubject<Void, BleAuthError> = .init()
    var passSubject2: PassthroughSubject<Void, BleAuthError> = .init()

    init(certMessage: String, uid: UInt64,macAddress: String, keySetting: XiaopengKeyDataSetting, sendBlock: @escaping BleAuthFlowSendBlock, authFactorBlock: @escaping BleAuthFlowEncryptFactorBlock) {
        self.certMessage = certMessage
        self.uid = uid
        self.keySetting = keySetting
        self.authFactorBlock = authFactorBlock
        self.indicatorHexStartIndex = self.certMessage.index(self.certMessage.startIndex, offsetBy: 0)
        self.indicatorHexEndIndex = self.certMessage.index(self.indicatorHexStartIndex, offsetBy: 16)
        self.keyIdHexStartIndex = self.certMessage.index(self.certMessage.startIndex, offsetBy: 16)
        self.keyIdHexEndIndex = self.certMessage.index(self.keyIdHexStartIndex, offsetBy: 32)
        self.authKeyHexStartIndex = self.certMessage.index(self.certMessage.startIndex, offsetBy: 48)
        self.authKeyHexEndIndex = self.certMessage.index(self.authKeyHexStartIndex, offsetBy: 64)
        self.certMessageHexStartIndex = self.certMessage.index(self.certMessage.startIndex, offsetBy: 112)
        self.certMessageHexEndIndex = self.certMessage.endIndex
        super.init(macAddress: macAddress, sendBlock: sendBlock)
    }

    func startFlow() -> AnyPublisher<Void, BleAuthError> {
        return self.auth0Request()
            .handleEvents(
                        receiveSubscription: { _ in print("auth0Request received subscription") },
                        receiveOutput: { _ in print("auth0Request received output") },
                        receiveCompletion: { completion in print("auth0Request completed with: \(completion)") },
                        receiveCancel: { print("auth0Request was cancelled") }
                    )
            .flatMap { [weak self] _ -> AnyPublisher<Void, BleAuthError> in
            print("auth1Request about to start") // 确认 auth1Request 被调用
            guard let self = self else {
                return Fail(error: .unKnown).eraseToAnyPublisher()
            }
            return self.auth1Request()
        }
        .eraseToAnyPublisher()
    }

    private func auth0Request() -> AnyPublisher<Void, BleAuthError> {
        return Future { promise in
            self.authStep = 1
            let rand0 = arc4random().littleEndian
            self.rand0 = rand0
            var timeStamp = Date().timeIntervalSince1970
            let deviceModel = BleAuthData.getDeviceModel()
            let deviceName = UIDevice.current.name
            let indicatorHexStr = String(self.certMessage[self.indicatorHexStartIndex..<self.indicatorHexEndIndex])
            let keyIdHexStr = String(self.certMessage[self.keyIdHexStartIndex..<self.keyIdHexEndIndex])
            self.hexKeyId = keyIdHexStr
            let authKeyHexStr = String(self.certMessage[self.authKeyHexStartIndex..<self.authKeyHexEndIndex])
            self.hexAuthKey = authKeyHexStr
            self.authFactorBlock(XPBleKeyV3DataProcessor.generateAuthKey(self.hexAuthKey ?? ""), nil, nil)
            var selfCalibrationArray: Array<Any>? = nil
            var selfCalibrationLen: UInt8 = 0
            if self.keySetting.useSelfCalibration == true {
                if self.keySetting.txPowerArray != nil {
                    selfCalibrationLen = UInt8(((self.keySetting.txPowerArray?.reduce(0) { total, string in
                        total + string.lengthOfBytes(using: .utf8)
                    } ?? 0)/2))
                    let dataArray = self.keySetting.txPowerArray?.compactMap({ string in
                        return Data.init(hexString: string)
                    })
                    selfCalibrationArray = dataArray
                }
            }

            var data = XPBleKeyV3DataProcessor.generateAuth0DataIndictor(indicatorHexStr, uid: self.uid, hexKeyId: keyIdHexStr, rand0: rand0, timeStamp: UInt64(timeStamp), isWelcome: self.keySetting.unlockIsWelcome, pollingSwitch: self.keySetting.pollingMode.rawValue, pollingEnableSwitch: self.keySetting.pollingEnableSwitch, unlockDistance: self.keySetting.unlockDistance, lockDistance: self.keySetting.lockDistance, selfCalibrationLen: selfCalibrationLen, selfCalibrationArray: selfCalibrationArray, deviceModel: deviceModel, bleName: deviceName, hexAuthKey: authKeyHexStr)
            guard let data = data else {
                promise(.failure(.writeFail))
                return
            }
            let dataParams = BleSendData(controlId: nil, sendData: [data])
            self.sendBlock(dataParams, { [weak self] in
                Log.i("auth0写入成功")
            }, {
                Log.i("auth0写入失败:")
                promise(.failure(.writeFail))
            })
            self.passSubject1
                        .first() // 确保我们只处理 `passSubject1` 的第一个完成事件
                        .sink(
                            receiveCompletion: { completion in
                                switch completion {
                                case .finished:
                                    print("passSubject1 completed.")
                                    promise(.success(())) // 只有 `passSubject1` 完成后再调用 `promise(.success(()))`
                                case .failure(let error):
                                    print("passSubject1 failed with error: \(error)")
                                    promise(.failure(error))
                                }
                            },
                            receiveValue: {
                                print("Received a message from passSubject1.")
                            }
                        )
                        .store(in: &self.cancellables)
        }
        .eraseToAnyPublisher()
    }

    private func auth1Request() -> AnyPublisher<Void, BleAuthError> {
        return Future { promise in
            self.authStep = 2
            let hexCertMessage = String(self.certMessage[self.certMessageHexStartIndex..<self.certMessageHexEndIndex])

            guard let sessionKey = self.sessionKey else {
                promise(.failure(.writeFail))
                return
            }
            guard let rand12 = self.rand12 else {
                promise(.failure(.writeFail))
                return
            }
            var data = XPBleKeyV3DataProcessor.generateAuth1DataRand12(rand12, hexCertMessage: hexCertMessage, sessionKey: sessionKey)
            guard let data = data else {
                promise(.failure(.writeFail))
                return
            }
            let dataParams = BleSendData(sendData: [data])
            self.sendBlock(dataParams, { [weak self] in
                Log.i("auth1写入成功")

            }, {
                Log.i("auth1写入失败:")
                promise(.failure(.writeFail))
            })
            self.passSubject2
                .sink(
                    receiveCompletion: { completion in
                        switch completion {
                        case .finished:
                            print("passSubject2 completed.")
                            promise(.success(()))
                        case .failure(let error):
                            print("passSubject2 failed with error: \(error)")
                            promise(.failure(error))
                        }
                    },
                    receiveValue: {
                        print("Received a message from passSubject1.")
                    }
                )
                .store(in: &self.cancellables) // 保存取消订阅的引用
        }
        .eraseToAnyPublisher()
    }
}

extension BleKeyV3AuthFlow: BleAuthProtocol {
    func receiveAuthStep1Data(_ rand01: UInt32?, _ rand1: UInt32) {
        Log.i("蓝牙鉴权 第一步获得随机数,rand01=\(rand01) ,rand1=\(rand1)")
        if rand01 == (self.rand0 ?? 0) + 1 {
            self.rand12 = rand1 + 2;
            self.sessionKey = XPBleKeyV3DataProcessor.generateSessionKey(self.hexAuthKey!, hexKeyId: self.hexKeyId!, rand0: self.rand0!, rand1: rand1)
            self.hmacKey =  XPBleKeyV3DataProcessor.generateHmacKey(self.hexAuthKey!, rand01: rand01!, rand12: self.rand12!)
            self.authFactorBlock(nil, self.sessionKey, self.hmacKey)
            self.passSubject1.send(completion: .finished)
        } else {
            self.passSubject1.send(completion: .failure(.auth01CheckFailed))
        }
    }

    func receiveAuthResult(_ authResult: Int, _ failReason: Int) {
        if authResult == 0 {
            self.passSubject2.send(completion: .finished)
        } else {
            self.passSubject2.send(completion: .failure(.execFail(code: failReason, msg: "")))
        }
    }
}

